from datetime import datetime
from .protocols.jsonrpc import JSONRPCProtocol, JSONRPCServerError
from .transports.transport import PRMClientTransport
from .client import RPCClient
import traceback

class RPCClientWrapper:
    def __init__(self, transport, publisher=None):
        self.transport = PRMClientTransport(transport)

        self.protocol = JSONRPCProtocol()
        self.publisher = publisher
        self.transport.publisher = publisher

        self.rpc_client = RPCClient(self.protocol, self.transport, self.publisher, retries=3)

        self.log = None

    def get_proxy(self, prefix=''):
        return self.rpc_client.get_proxy(prefix)

    def _log(self, message):
        if self.log:
            self.log(message)
        elif self.publisher:
            self.publisher.publish(message)

    def call(self, method, *args, **kwargs):
        try:
            _strArg = ','.join([str(arg) for arg in args] + ['{}={}'.format(k, v) for k, v in kwargs.items()])
            self._log('[rpc send]  {}({})'.format(method, _strArg))
            # print("rpc-call-args:" + str(args))
            # print("rpc-call-kwargs:" + str(kwargs))
            response = getattr(self.get_proxy(), method)(*args, **kwargs)
            response = response.serialize()

            if hasattr(response, 'id') and not hasattr(response, 'unique_id'):
                response['unique_id'] = response[id]
            self._log('[rpc recv]  {}({}) <-<<  {} \n'.format(method, _strArg, response))

            if response is None:
                #raise JSONRPCServerError('Timed out waiting for response from test engine in test: ' + str(method))
                raise RuntimeError('Timed out waiting for response from test engine in test: ' + str(method))
            if hasattr(response, 'error'):
                #raise JSONRPCServerError('Test Engine error: ' + str(response._jsonrpc_error_code) + ':' + response.error)
                raise RuntimeError('Test Engine error: ' + str(response._jsonrpc_error_code) + ':' + response.error)

        except Exception as e:
            self._log('[rpc recv]  {}({}) <-<<  {} \n'.format(method, _strArg, e))
            raise e
            # response.error

        return response
